```java
import org.jfree.chart.ChartFactory;
import org.jfree.chart.ChartPanel;
import org.jfree.chart.JFreeChart;
import org.jfree.chart.plot.XYPlot;
import org.jfree.chart.renderer.xy.CandlestickRenderer;
import org.jfree.data.xy.DefaultHighLowDataset;
import org.jfree.data.xy.OHLCDataset;

import javax.swing.*;
import java.awt.*;
import java.util.Date;

public class KLineChartExample {

    public static void main(String[] args) {
        EventQueue.invokeLater(() -> {
            JFrame frame = new JFrame();

            // 创建数据集
            OHLCDataset dataset = createDataset();

            // 创建图表
            JFreeChart chart = ChartFactory.createCandlestickChart(
                    "K 线图示例", // 图表标题
                    "时间", // X轴标签
                    "价格", // Y轴标签
                    dataset, // 数据集
                    false // legend
            );

            XYPlot plot = (XYPlot)chart.getPlot();
            plot.setRenderer(new CandlestickRenderer());

            ChartPanel chartPanel = new ChartPanel(chart);
            frame.add(chartPanel);
            frame.pack();
            frame.setLocationRelativeTo(null);
            frame.setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);
            frame.setVisible(true);
        });
    }

    private static OHLCDataset createDataset() {
        final int DATA_COUNT = 10;
        Date[] dates = new Date[DATA_COUNT];
        double[] opens = new double[DATA_COUNT];
        double[] highs = new double[DATA_COUNT];
        double[] lows = new double[DATA_COUNT];
        double[] closes = new double[DATA_COUNT];
        double[] volumes = new double[DATA_COUNT];

        // 测试数据填充，以当前时间为基准，生成10个点的随机数据
        long currentTime = System.currentTimeMillis();
        for (int i = 0; i < DATA_COUNT; i++) {
            dates[i] = new Date(currentTime + 86400000L * i); // 以天为单位
            opens[i] = Math.random() * 100;
            highs[i] = opens[i] + Math.random() * 10;
            lows[i] = opens[i] - Math.random() * 10;
            closes[i] = opens[i] + Math.random() * 5 - 2.5;
            volumes[i] = Math.random() * 1000;
        }

        return new DefaultHighLowDataset("K 线图", dates, highs, lows, opens, closes, volumes);
    }
}
```

在这个示例中，`createDataset`方法生成了一些随机的价格数据。实际应用中，你需要根据你的数据源来生成这些`Date`、开盘价、最高价、最低价和收盘价的数组。

